  }
];

export default function VideosPage() {
  const [selectedCategory, setSelectedCategory] = useState<'all' | 'trailer' | 'gameplay' | 'interview' | 'analysis'>('all');

  const filteredVideos = selectedCategory === 'all' 
    ? MOCK_VIDEOS 
    : MOCK_VIDEOS.filter(v => v.category === selectedCategory);

  const getCategoryColor = (category: string) => {
    switch(category) {
      case 'trailer': return 'neon-pink';
      case 'gameplay': return 'neon-blue';
      case 'interview': return 'neon-purple';
      case 'analysis': return 'neon-magenta';
      default: return 'gray-400';
    }
  };

  return (
    <div className="min-h-screen p-4 md:p-8">
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-4xl md:text-5xl font-black font-orbitron tracking-wider text-glow-pink uppercase mb-2">
          VIDEO GALLERY
        </h1>
        <p className="text-gray-400 text-sm md:text-base">
          Watch official trailers, gameplay reveals, and exclusive behind-the-scenes content
        </p>
      </div>

      {/* Category Filter */}
      <div className="flex flex-wrap gap-3 mb-8">
        {(['all', 'trailer', 'gameplay', 'interview', 'analysis'] as const).map((category) => (
          <button
            key={category}
            onClick={() => setSelectedCategory(category)}
            className={`px-4 py-2 text-xs font-bold tracking-widest uppercase rounded-lg transition-all duration-200 ${
              selectedCategory === category
                ? 'bg-neon-pink text-white neon-glow-pink'
                : 'bg-gray-800/40 text-gray-400 hover:text-white hover:bg-gray-700/60'
            }`}
          >
            {category}
          </button>
        ))}
      </div>

      {/* Video Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredVideos.map((video, index) => (
          <motion.div
            key={video.id}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: index * 0.1 }}
          >
            <GlassCard variant="default" blur="medium" className="overflow-hidden hover:scale-[1.02] transition-transform duration-200 cursor-pointer group">
              {/* Thumbnail */}
              <div className="relative aspect-video overflow-hidden">
                <div 
                  className="absolute inset-0 bg-cover bg-center group-hover:scale-110 transition-transform duration-500"
                  style={{ backgroundImage: `url('${video.thumbnail}')` }}
                />
                <div className="absolute inset-0 bg-gradient-to-t from-dark-navy via-transparent to-transparent" />

                {/* Play Button Overlay */}
                <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-200">
                  <div className="w-16 h-16 rounded-full bg-neon-pink flex items-center justify-center neon-glow-pink">
                    <svg className="w-8 h-8 text-white fill-current ml-1" viewBox="0 0 24 24">
                      <path d="M8 5v14l11-7z" />
                    </svg>
                  </div>
                </div>

                {/* Duration Badge */}
                <div className="absolute bottom-2 right-2 px-2 py-1 bg-black/80 rounded text-xs font-bold text-white">
                  {video.duration}
                </div>

                {/* Category Badge */}
                <div className={`absolute top-2 left-2 px-2 py-1 bg-${getCategoryColor(video.category)}/20 border border-${getCategoryColor(video.category)} rounded text-[10px] font-bold text-${getCategoryColor(video.category)} uppercase tracking-wider`}>
